def call_gpt5_with_responses_api(prompt: str, model: str = None, max_output_tokens: int = 4000, temperature: float = 0.7) -> str:
    api_key = get_openai_api_key()
    if OpenAI is None:
        strict = os.environ.get("OFFLINE_MODE", "0") != "1"
        if strict:
            raise RuntimeError("OpenAI client not installed and OFFLINE_MODE disabled")
        return "[OFFLINE] LLM unavailable."
    client = OpenAI()
    model = model or os.environ.get("OPENAI_MODEL", "gpt-4.1-mini")
    responses_kwargs = {
        "model": model,
        "input": [{"role": "user", "content": [{"type": "input_text", "text": prompt}]}],
        "max_output_tokens": max_output_tokens,
        "temperature": max(0.0, min(2.0, temperature)),
    }
    resp = client.responses.create(**responses_kwargs)
    def extract_response(resp_obj):
        if hasattr(resp_obj, "output_text") and isinstance(resp_obj.output_text, str):
            return resp_obj.output_text
        try:
            output = getattr(resp_obj, "output", None)
            if isinstance(output, list) and output:
                content = output[0].get("content") if isinstance(output[0], dict) else None
                if isinstance(content, list) and content:
                    txt = content[0].get("text")
                    if isinstance(txt, str):
                        return txt
        except Exception:
            pass
        return str(resp_obj)
    return extract_response(resp)

